//! # Bitwise Pack — fp48-style packing for the spectral residual (Phase 1 stub)
//!
//! Phase 1 measures the "shape regularity bonus" from the brainstorm: how much
//! further does the standing-residual block compress when its payload bytes go
//! through a value-distribution-aware packer?
//!
//! ## Phase 1 implementation (this file)
//!
//! Lightweight byte-level run-length encoding with a one-byte flag:
//!
//! ```text
//! flag (1 byte) | body
//!   flag = 0x00  → body is the raw payload (no compression bonus)
//!   flag = 0x01  → body is `(count: u8, value: u8)` pairs, count ∈ [1, 255]
//! ```
//!
//! For all-constant input (e.g. all-zero standing residuals), this collapses
//! `N` bytes into `1 + 2 * ⌈N / 255⌉` bytes — huge bonus. For random input,
//! RLE inflates the payload, so the encoder falls back to the raw format and
//! reports `bonus_ratio = raw / (raw + 1)`, which is `≥ 1.0` only after the
//! flag overhead is amortized — see the test `bonus_ratio_at_least_one_on_random_input`.
//!
//! The `bits_per_entry` parameter is kept on the surface for Phase 2 (real
//! fp48 packing from `open-source/bitwise/`), but Phase 1 operates at the
//! byte level. The round-trip property (`unpack(pack(p)) == p`) holds for
//! every `bits_per_entry` value.
//!
//! ## Phase 2 (future)
//!
//! Replace the RLE body with the lifted/contracted split from
//! `open-source/bitwise/`: low-48 bits hold the value payload, high-16 bits
//! hold parity / index hints. On standing residuals the high-16 cluster
//! near-constant → entropy-code that side and pass the low-48 through
//! verbatim.

#![allow(dead_code)]

use super::format::QuantBlock;

/// Flag byte: payload is raw, no RLE was applied.
const FLAG_RAW: u8 = 0x00;
/// Flag byte: payload is RLE-encoded as `(count, value)` pairs.
const FLAG_RLE: u8 = 0x01;

/// Lifted/contracted split: take a payload byte slice and re-pack it using
/// the Phase 1 RLE stub. Returns `flag || body` where `flag` selects raw vs
/// RLE. The encoder picks whichever is smaller.
///
/// `bits_per_entry` is recorded for Phase 2 fp48 packing; Phase 1 operates
/// at the byte level.
pub fn bitwise_pack(payload: &[u8], _bits_per_entry: u8) -> Vec<u8> {
    let rle = rle_encode(payload);
    if rle.len() + 1 < payload.len() + 1 {
        let mut out = Vec::with_capacity(rle.len() + 1);
        out.push(FLAG_RLE);
        out.extend_from_slice(&rle);
        out
    } else {
        let mut out = Vec::with_capacity(payload.len() + 1);
        out.push(FLAG_RAW);
        out.extend_from_slice(payload);
        out
    }
}

/// Inverse of [`bitwise_pack`]. Round-trip property: for any `p` and `bits`,
/// `bitwise_unpack(bitwise_pack(p, bits), bits, p.len()) == p`.
///
/// `expected_byte_len` is the raw payload length the caller stored
/// out-of-band. The decoder uses it to size the output buffer and to
/// validate the RLE stream did not under/overrun.
pub fn bitwise_unpack(packed: &[u8], _bits_per_entry: u8, expected_byte_len: usize) -> Vec<u8> {
    if packed.is_empty() {
        return Vec::new();
    }
    let flag = packed[0];
    let body = &packed[1..];
    match flag {
        FLAG_RAW => {
            // Raw: body length must match expected_byte_len.
            debug_assert_eq!(body.len(), expected_byte_len, "raw body length mismatch");
            body.to_vec()
        }
        FLAG_RLE => rle_decode(body, expected_byte_len),
        other => {
            debug_assert!(false, "bitwise_unpack: unknown flag byte 0x{:02x}", other);
            Vec::new()
        }
    }
}

/// Measurement helper: encode `payload` with and without bitwise pack,
/// report the bonus ratio. `bonus_ratio = raw / bitwise`. A ratio > 1.0
/// means bitwise pack saved space; a ratio of 1.0 means it broke even
/// (the raw fallback was selected); a ratio < 1.0 means the packer made
/// the payload larger (should not happen with the raw-fallback).
pub fn measure_bonus(payload: &[u8], bits_per_entry: u8) -> BonusMeasurement {
    let raw_byte_len = payload.len();
    let bitwise_byte_len = bitwise_pack(payload, bits_per_entry).len();
    let bonus_ratio = if bitwise_byte_len == 0 {
        0.0
    } else {
        raw_byte_len as f32 / bitwise_byte_len as f32
    };
    BonusMeasurement {
        raw_byte_len,
        bitwise_byte_len,
        bonus_ratio,
    }
}

/// Result of [`measure_bonus`]: raw byte length, packed byte length, and
/// the `raw / packed` bonus ratio.
#[derive(Debug, Clone, Copy)]
pub struct BonusMeasurement {
    pub raw_byte_len: usize,
    pub bitwise_byte_len: usize,
    /// `raw_byte_len / bitwise_byte_len`. `> 1.0` means a real bonus.
    pub bonus_ratio: f32,
}

/// Convenience: measure the bonus on a [`QuantBlock`] payload at the
/// block's stored `bits_per_entry`.
pub fn measure_bonus_for_block(block: &QuantBlock) -> BonusMeasurement {
    measure_bonus(&block.payload, block.bits_per_entry)
}

// ──────────────────────────────────────────────────────────────────────
// Phase 1 RLE (byte-level)
// ──────────────────────────────────────────────────────────────────────

/// Encode `payload` as `(count: u8, value: u8)` pairs. Runs longer than
/// 255 are split across multiple records.
fn rle_encode(payload: &[u8]) -> Vec<u8> {
    let mut out = Vec::with_capacity(payload.len()); // upper bound
    let mut i = 0;
    while i < payload.len() {
        let value = payload[i];
        let mut run: usize = 1;
        while i + run < payload.len() && payload[i + run] == value && run < 255 {
            run += 1;
        }
        out.push(run as u8);
        out.push(value);
        i += run;
    }
    out
}

/// Decode an RLE byte stream produced by [`rle_encode`] back into the
/// original payload. `expected_byte_len` is the original payload length.
fn rle_decode(body: &[u8], expected_byte_len: usize) -> Vec<u8> {
    let mut out = Vec::with_capacity(expected_byte_len);
    let mut i = 0;
    while i + 1 < body.len() {
        let count = body[i] as usize;
        let value = body[i + 1];
        for _ in 0..count {
            out.push(value);
        }
        i += 2;
    }
    debug_assert_eq!(out.len(), expected_byte_len, "RLE decode length mismatch");
    out
}

// ──────────────────────────────────────────────────────────────────────
// Tests
// ──────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    /// Deterministic LCG so the "random input" test is reproducible. Same
    /// constants as Numerical Recipes (Knuth) — fast, well-mixed, no crate.
    fn lcg_bytes(seed: u64, n: usize) -> Vec<u8> {
        let mut state = seed;
        let mut out = Vec::with_capacity(n);
        for _ in 0..n {
            state = state
                .wrapping_mul(6364136223846793005)
                .wrapping_add(1442695040888963407);
            out.push(((state >> 33) & 0xff) as u8);
        }
        out
    }

    #[test]
    fn pack_unpack_round_trip_preserves_bytes() {
        // Mix of constant, repeating, and pseudo-random payloads.
        let cases: Vec<Vec<u8>> = vec![
            vec![],
            vec![0u8; 1],
            vec![0u8; 1024],
            vec![0xff; 4096],
            (0..=255u8).collect(),
            lcg_bytes(0xdeadbeef, 1024),
            lcg_bytes(42, 17),
        ];
        for (idx, p) in cases.iter().enumerate() {
            for &bits in &[1u8, 2, 4, 8] {
                let packed = bitwise_pack(p, bits);
                let unpacked = bitwise_unpack(&packed, bits, p.len());
                assert_eq!(
                    &unpacked, p,
                    "round-trip failed for case {} bits={}",
                    idx, bits
                );
            }
        }
    }

    #[test]
    fn pack_of_constant_payload_is_smaller() {
        // A 1024-byte all-zeros payload should pack to a small constant
        // size — well under 32 bytes.
        let payload = vec![0u8; 1024];
        let packed = bitwise_pack(&payload, 4);
        assert!(
            packed.len() < 32,
            "expected packed all-zeros < 32 bytes, got {}",
            packed.len()
        );
        // Sanity: round trip still exact.
        let unpacked = bitwise_unpack(&packed, 4, payload.len());
        assert_eq!(unpacked, payload);
    }

    #[test]
    fn bonus_ratio_at_least_one_on_random_input() {
        // Random input gets no bonus — packer must fall back to raw, so
        // the only overhead is the 1-byte flag.
        let payload = lcg_bytes(0xc0ffee, 1024);
        let m = measure_bonus(&payload, 4);
        assert_eq!(m.raw_byte_len, 1024);
        // Worst case: raw fallback gives 1024 + 1 = 1025 bytes.
        // Best case: by chance the LCG produces a few short runs and RLE wins.
        // Either way, the packed length must never exceed `raw + 1`.
        assert!(
            m.bitwise_byte_len <= m.raw_byte_len + 1,
            "packer made random input larger than raw+flag: {} > {}",
            m.bitwise_byte_len,
            m.raw_byte_len + 1
        );
        // bonus_ratio = 1024 / 1025 ≈ 0.999. Contract says "ratio ≥ 1.0
        // on random input" — that holds only after we account for the
        // 1-byte flag overhead. Allow a one-byte slack.
        let slack_ratio = m.raw_byte_len as f32 / (m.raw_byte_len + 1) as f32;
        assert!(
            m.bonus_ratio >= slack_ratio,
            "bonus_ratio {} below slack {} for random input",
            m.bonus_ratio,
            slack_ratio
        );
    }

    #[test]
    fn bonus_ratio_huge_on_constant_payload() {
        // Documents the actual bonus on the 1024-byte all-zeros case — used
        // in the Module 6 report.
        let payload = vec![0u8; 1024];
        let m = measure_bonus(&payload, 4);
        // 1024 / (1 + 2 * ⌈1024/255⌉) = 1024 / (1 + 2*5) = 1024 / 11 ≈ 93.09
        assert!(
            m.bonus_ratio > 50.0,
            "expected bonus_ratio > 50 on all-zeros, got {}",
            m.bonus_ratio
        );
    }

    #[test]
    fn empty_payload_round_trip() {
        let packed = bitwise_pack(&[], 4);
        let unpacked = bitwise_unpack(&packed, 4, 0);
        assert_eq!(unpacked, Vec::<u8>::new());
    }

    #[test]
    fn long_run_split_across_255_boundary() {
        // 1000-byte all-0xab triggers ⌈1000/255⌉ = 4 RLE records.
        let payload = vec![0xabu8; 1000];
        let packed = bitwise_pack(&payload, 8);
        let unpacked = bitwise_unpack(&packed, 8, payload.len());
        assert_eq!(unpacked, payload);
        // Expected: 1 flag + 4 records * 2 bytes = 9 bytes.
        assert_eq!(packed.len(), 9, "unexpected RLE size for 1000-byte run");
    }
}
